export default function Renderer({ content, renderMarkdown, messageIndex }) {
  const api = useYumina();
  const route = api.variables.current_route;
  const hasChosen = route !== "none";
  const msgs = api.messages || [];
  const isLastMsg = messageIndex === msgs.length - 1;
  const [ruleInput, setRuleInput] = React.useState("");
  const currentRule = String(api.variables.custom_rule || "没有特殊规则。");

  return (
    <div>
      <div
        style={{ color: "#e2e8f0", lineHeight: 1.7 }}
        dangerouslySetInnerHTML={{ __html: renderMarkdown(content) }}
      />

      {messageIndex === 0 && !hasChosen && (
        <div style={{ display: "flex", gap: "12px", marginTop: "16px" }}>
          <button
            onClick={() => {
              api.setVariable("current_route", "dark");
              api.executeAction("choose-dark");
              api.switchGreeting?.(1);
            }}
            style={{ flex: 1, padding: "16px", background: "linear-gradient(135deg, #1e1b4b, #312e81)", border: "1px solid #4338ca", borderRadius: "12px", color: "#c7d2fe", fontSize: "15px", fontWeight: "bold", cursor: "pointer", transition: "transform 0.15s" }}
            onMouseOver={(e) => e.currentTarget.style.transform = "scale(1.03)"}
            onMouseOut={(e) => e.currentTarget.style.transform = "scale(1)"}
          >
            进入黑暗洞穴
          </button>
          <button
            onClick={() => {
              api.setVariable("current_route", "light");
              api.executeAction("choose-light");
              api.switchGreeting?.(2);
            }}
            style={{ flex: 1, padding: "16px", background: "linear-gradient(135deg, #365314, #4d7c0f)", border: "1px solid #65a30d", borderRadius: "12px", color: "#ecfccb", fontSize: "15px", fontWeight: "bold", cursor: "pointer", transition: "transform 0.15s" }}
            onMouseOver={(e) => e.currentTarget.style.transform = "scale(1.03)"}
            onMouseOut={(e) => e.currentTarget.style.transform = "scale(1)"}
          >
            走向阳光草地
          </button>
        </div>
      )}

      {isLastMsg && (
        <div style={{ marginTop: "12px", padding: "12px", background: "rgba(30,41,59,0.5)", borderRadius: "8px", border: "1px solid #334155" }}>
          <div style={{ fontSize: "12px", color: "#94a3b8", marginBottom: "6px" }}>世界规则：{currentRule}</div>
          <div style={{ display: "flex", gap: "8px" }}>
            <input
              type="text"
              value={ruleInput}
              onChange={(e) => setRuleInput(e.target.value)}
              placeholder="输入新规则..."
              style={{ flex: 1, padding: "6px 10px", background: "#1e293b", border: "1px solid #475569", borderRadius: "6px", color: "#e2e8f0", fontSize: "13px", outline: "none" }}
              onKeyDown={(e) => { if (e.key === "Enter" && ruleInput.trim()) { api.setVariable("custom_rule", ruleInput.trim()); setRuleInput(""); } }}
            />
            <button
              onClick={() => { if (ruleInput.trim()) { api.setVariable("custom_rule", ruleInput.trim()); setRuleInput(""); } }}
              style={{ padding: "6px 14px", background: "#4338ca", borderRadius: "6px", color: "#e0e7ff", fontSize: "13px", fontWeight: "600", cursor: "pointer", border: "none" }}
            >
              应用
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
